powershell -nop -ep bypass -c "$oP='C:\Temp\OpenShares_$(Get-Date -Format ''yyyyMMdd_HHmm'').csv';$tF='C:\Temp\computers.txt';$dS=8;$jT=5;$oD=Split-Path $oP -Parent;if(-not(Test-Path $oD)){New-Item -Path $oD -ItemType Directory -Force|Out-Null};function gC(){if(Test-Path $tF){$c=Get-Content $tF|?{$_-match'\S'}|%{$_.Trim()};Write-Host \"Loaded $($c.Count) targets from file\";return $c}else{Write-Warning \"File not found\";return @()}};$comps=gC;$res=@();foreach($comp in $comps){if(-not$comp){continue};Write-Host \"Tested: $comp\" -ForegroundColor Gray;try{$sh=gwmi -Class Win32_Share -ComputerName $comp -EA 0|?{$_.Type -eq 0};foreach($s in $sh){$p=\"\\$comp\$($s.Name)\";$acc=$false;$broad=$false;try{if(Test-Path $p -EA 0){$acc=$true;$sec=gwmi -Class Win32_LogicalShareSecuritySetting -Filter \"Name='$($s.Name)'\" -ComputerName $comp -EA 0;if($sec){$sd=$sec.GetSecurityDescriptor().Descriptor;foreach($ace in $sd.DACL){$t=$ace.Trustee.Name;if($t -match 'Everyone|Authenticated|Users|Domain Users'){$broad=$true;break}}}}}}catch{}if($acc -and $broad){$obj=[PSCustomObject]@{C=$comp.ToUpper();S=$s.Name;P=$p;D=$s.Description;TS=Get-Date};$res+=$obj;Write-Host \"  [!] Open: $p\" -ForegroundColor Yellow}}}catch{};$sl=$dS+(Get-Random -Min (-$jT) -Max $jT);if($sl-gt0){Start-Sleep -Seconds $sl}};$res|Export-Csv -Path $oP -NoTypeInformation -EA 0;if($res.Count -gt 0){Write-Host \"Found $($res.Count) open shares.\" -ForegroundColor Yellow};$res|ft C,S,P -AutoSize"
